import sys
import pymysql
from urllib.parse import parse_qs, urlencode

def request_handler(request):
    if request.method == 'GET':
        params = parse_qs(request.url)

        host = 'your_cloudsql_instance'
        user = 'your_username'
        password = 'your_password'
        db = 'your_database'

        connection = pymysql.connect(host=host,
                                      user=user,
                                      password=password,
                                      db=db)

        cursor = connection.cursor()

        search_query = "SELECT * FROM your_table WHERE "
        for key, value in params.items():
            if key != 'page' and key != 'limit':  # Assuming 'page' and 'limit' are used for pagination
                search_query += f"{key} LIKE '%{value[0]}%' AND "
        search_query = search_query[:-4]  # Remove the last 'AND' before querying the database.

        cursor.execute(search_query)
        results = cursor.fetchall()

        response = f"Results: {urlencode(list(map(lambda x: dict(x), results)))}"
        connection.close()

        return response.encode('utf-8')